from flask import Request, jsonify
import os
import hmac
import hashlib
import logging

logging.basicConfig(level=logging.INFO)

WEBHOOK_SECRET = os.environ.get("WEBHOOK_SECRET", "")

def _verify_signature(raw_body: bytes, signature: str) -> bool:
    if not WEBHOOK_SECRET:
        return False
    expected = hmac.new(
        WEBHOOK_SECRET.encode("utf-8"),
        raw_body,
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(expected, signature or "")

def payment_webhook(request: Request):
    if request.method != "POST":
        return jsonify({"error": "method_not_allowed"}), 405

    raw_body = request.get_data(cache=False, as_text=False)
    signature = request.headers.get("X-Signature", "")

    if not _verify_signature(raw_body, signature):
        logging.warning("Invalid webhook signature")
        return jsonify({"error": "invalid_signature"}), 401

    try:
        event = request.get_json(force=True, silent=False)
    except Exception:
        return jsonify({"error": "invalid_json"}), 400

    event_type = event.get("type")
    event_id = event.get("id")
    logging.info("Received webhook event id=%s type=%s", event_id, event_type)

    if event_type == "payment_succeeded":
        return jsonify({"status": "ok", "processed": True}), 200
    elif event_type == "payment_failed":
        return jsonify({"status": "ok", "processed": True}), 200

    return jsonify({"status": "ok", "processed": False}), 200